Below is a **complete, self‑contained** OCaml binding for a (hypothetical) C++ class that iterates over the frames of a *pcapng* file.  
The design tries to keep the hot path (the per‑frame callback) as cheap as possible while still giving the OCaml user a pleasant, idiomatic API.

*   The OCaml side sees only opaque types (`pcapng` and `frame`).  
*   The only allocation that happens per frame is the OCaml record that is handed to the user‑supplied callback – the raw packet bytes are **not copied**; they are exposed as a `Bigarray` that points directly into the C++ memory.  
*   The iterator runs completely in C++ and only calls back into OCaml once per frame.  
*   The OCaml runtime lock is released while the C++ iterator walks, so the whole loop runs in parallel with other OCaml threads (if the program uses them).

---

## 1. The OCaml interface (`pcapng.mli`)

```ocaml
(* -------------------------------------------------------------------- *)
(*  pcapng.mli – public interface                                         *)
(* -------------------------------------------------------------------- *)

(** Opaque handle to an opened pcapng file. *)
type t

(** Opaque handle to a single frame.  The value is only valid while the
    iterator is running – it must not be stored or returned from the
    callback. *)
type frame

(** Open a pcapng file.  Raises [Failure] if the file cannot be opened. *)
val open_file : string -> t

(** Close a file that was previously opened with [open_file].  After this
    call the handle must not be used again. *)
val close : t -> unit

(** {1 Accessors for a single frame } *)

val timestamp : frame -> int64
(** Timestamp of the frame (nanoseconds since the Unix epoch). *)

val captured_len : frame -> int
(** Number of bytes captured in the file (the length of the [data] below). *)

val original_len : frame -> int
(** Original length of the Ethernet frame on the wire. *)

val data : frame -> (char, Bigarray.int8_unsigned_elt, Bigarray.c_layout) Bigarray.Array1.t
(** A read‑only view of the raw packet bytes.  The returned bigarray points
    directly into the C++ memory; it must **not** be freed or mutated by
    OCaml.  The view is only guaranteed to be valid for the duration of the
    callback. *)

(** {1 Iteration } *)

val iter : t -> (frame -> unit) -> unit
(** Iterate over all frames in the file, invoking the supplied callback for
    each frame.  The callback runs on the OCaml side, but the iterator itself
    runs in C++ without allocating any OCaml objects except for the tiny
    record that represents the current frame.  Exceptions raised by the
    callback are propagated to the caller of [iter]. *)
```

---

## 2. The C / C++ stub (`pcapng_stubs.c`)

The stub file is a **single translation unit** that can be compiled with a C++ compiler
(e.g. `g++ -std=c++17 -I$(OCAML_HOME)/include ...`).  
All OCaml‑C glue is written in the usual “C” style, but the heavy work is done
in C++.

```c
/* -------------------------------------------------------------------- */
/*  pcapng_stubs.c – OCaml <-> C++ glue                                   */
/* -------------------------------------------------------------------- */

#define CAML_NAME_SPACE        /* avoid name clashes */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/callback.h>
#include <inttypes.h>
#include <stddef.h>
#include <string.h>

/* -------------------------------------------------------------------- */
/*  Minimal C++ façade for libpcapng (replace with the real headers).   */
/* -------------------------------------------------------------------- */
#ifdef __cplusplus
extern "C" {
#endif

/* The real library would expose something like this: */
namespace libpcapng {

struct Frame {
    uint64_t timestamp;   /* ns since epoch */
    uint32_t caplen;       /* bytes stored in the file */
    uint32_t origlen;      /* bytes on the wire */
    const uint8_t* data;   /* pointer to raw bytes (valid as long as the iterator lives) */
};

class Iterator {
public:
    Iterator(const char* filename);          /* open file */
    ~Iterator();                              /* close file */

    bool next(Frame& out);                    /* advance, return false on EOF */
    /* No copying of Frame objects – the iterator owns the memory that
       Frame::data points into; it stays valid until the next call to next(). */
};

} /* namespace libpcapng */

#ifdef __cplusplus
}
#endif
/* -------------------------------------------------------------------- */

using libpcapng::Iterator;
using libpcapng::Frame;

/* -------------------------------------------------------------------- */
/*  OCaml custom blocks                                                    */
/* -------------------------------------------------------------------- */

static void finalize_pcapng(value v)
{
    Iterator* it = *(Iterator**)Data_custom_val(v);
    delete it;
}

/* The block contains a single pointer (Iterator*) */
static struct custom_operations pcapng_ops = {
    "pcapng.iterator",
    finalize_pcapng,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_fixed_length_default
};

/* -------------------------------------------------------------------- */
/*  Helper: allocate a fresh OCaml frame value (no copy of the packet)   */
/* -------------------------------------------------------------------- */
static value alloc_frame(const Frame* f)
{
    /* OCaml layout:
       type frame = {
         timestamp : int64;
         caplen    : int;
         origlen   : int;
         data      : bytes_bigarray;
       }
       The record is represented as a block with 4 fields (tag = 0).   */
    CAMLparam0();
    CAMLlocal5(v_rec, v_ts, v_caplen, v_origlen, v_big);

    /* timestamp – copy the 64‑bit value */
    v_ts = caml_copy_int64((int64_t)f->timestamp);

    /* caplen / origlen – fit into a (signed) OCaml int (31‑bit on 32‑bit,
       63‑bit on 64‑bit platforms).  The pcapng spec guarantees they fit. */
    v_caplen  = Val_int((int)f->caplen);
    v_origlen = Val_int((int)f->origlen);

    /* data – a bigarray that points directly at the C++ buffer.
       The bigarray is *read‑only*; we mark it as a C layout array of
       unsigned 8‑bit integers. */
    intnat dims[1] = { (intnat)f->caplen };
    v_big = caml_ba_alloc(CAML_BA_UINT8 | CAML_BA_C_LAYOUT, 1, (void*)f->data, dims);

    /* Assemble the record */
    v_rec = caml_alloc(4, 0);          /* 4 fields, tag = 0 */
    Store_field(v_rec, 0, v_ts);
    Store_field(v_rec, 1, v_caplen);
    Store_field(v_rec, 2, v_origlen);
    Store_field(v_rec, 3, v_big);

    CAMLreturn(v_rec);
}

/* -------------------------------------------------------------------- */
/*  OCaml entry points                                                    */
/* -------------------------------------------------------------------- */

/* val open_file : string -> t */
CAMLprim value caml_pcapng_open_file(value v_fname)
{
    CAMLparam1(v_fname);
    CAMLlocal1(v_block);

    const char* fname = String_val(v_fname);
    Iterator* it = nullptr;

    /* C++ constructor may throw – translate to an OCaml exception */
    try {
        it = new Iterator(fname);
    } catch (const std::exception& e) {
        caml_failwith(e.what());
    } catch (...) {
        caml_failwith("pcapng: unknown error while opening file");
    }

    v_block = caml_alloc_custom(&pcapng_ops, sizeof(Iterator*), 0, 1);
    Iterator** p = (Iterator**)Data_custom_val(v_block);
    *p = it;

    CAMLreturn(v_block);
}

/* val close : t -> unit */
CAMLprim value caml_pcapng_close(value v_it)
{
    CAMLparam1(v_it);
    /* The custom block’s finalizer already deletes the iterator,
       but we provide an explicit close for symmetry. */
    Iterator* it = *(Iterator**)Data_custom_val(v_it);
    delete it;
    /* Overwrite the pointer so that a later use crashes loudly */
    *(Iterator**)Data_custom_val(v_it) = nullptr;
    CAMLreturn(Val_unit);
}

/* val iter : t -> (frame -> unit) -> unit */
CAMLprim value caml_pcapng_iter(value v_it, value v_closure)
{
    CAMLparam2(v_it, v_closure);
    CAMLlocal1(v_frame);

    Iterator* it = *(Iterator**)Data_custom_val(v_it);
    if (it == nullptr) caml_failwith("pcapng: iterator already closed");

    /* Release the OCaml runtime lock while we walk the C++ iterator.
       The lock will be reacquired for every callback. */
    caml_release_runtime_system();

    Frame cur;
    while (it->next(cur)) {
        /* Re‑acquire the lock, build the OCaml frame value, call back,
           then release again – this pattern keeps the lock held only
           during the actual OCaml call. */
        caml_acquire_runtime_system();

        v_frame = alloc_frame(&cur);
        /* The callback may raise; we propagate the exception outwards. */
        caml_callback(v_closure, v_frame);

        caml_release_runtime_system();
    }

    caml_acquire_runtime_system();   /* make sure we are back in OCaml land */
    CAMLreturn(Val_unit);
}

/* -------------------------------------------------------------------- */
/*  Accessors – they operate on the temporary frame value handed to the  */
/*  callback.  No allocation, just read the fields.                      */
/* -------------------------------------------------------------------- */

/* val timestamp : frame -> int64 */
CAMLprim value caml_pcapng_timestamp(value v_frame)
{
    CAMLparam1(v_frame);
    value v_ts = Field(v_frame, 0);
    CAMLreturn(v_ts);
}

/* val captured_len : frame -> int */
CAMLprim value caml_pcapng_captured_len(value v_frame)
{
    CAMLparam1(v_frame);
    CAMLreturn(Field(v_frame, 1));
}

/* val original_len : frame -> int */
CAMLprim value caml_pcapng_original_len(value v_frame)
{
    CAMLparam1(v_frame);
    CAMLreturn(Field(v_frame, 2));
}

/* val data : frame -> bigarray */
CAMLprim value caml_pcapng_data(value v_frame)
{
    CAMLparam1(v_frame);
    CAMLreturn(Field(v_frame, 3));
}

/* -------------------------------------------------------------------- */
/*  Registration of the primitives (for newer OCaml versions)           */
/* -------------------------------------------------------------------- */
#if OCAML_VERSION_MAJOR >= 4 && OCAML_VERSION_MINOR >= 12
static struct caml_named_value caml_named_values[] = {
    { "pcapng_open_file", caml_pcapng_open_file },
    { "pcapng_close",     caml_pcapng_close },
    { "pcapng_iter",      caml_pcapng_iter },
    { "pcapng_timestamp", caml_pcapng_timestamp },
    { "pcapng_captured_len", caml_pcapng_captured_len },
    { "pcapng_original_len", caml_pcapng_original_len },
    { "pcapng_data",      caml_pcapng_data },
    { NULL, NULL }
};

CAMLprim value caml_pcapng_register_primitives(value unit)
{
    caml_register_named_values(caml_named_values);
    return Val_unit;
}
#endif
```

### How the stub works

| OCaml call | What the stub does | Where the hot loop lives |
|------------|-------------------|--------------------------|
| `open_file` | `new Iterator(fname)` – C++ opens the file. | – |
| `close` | `delete Iterator` (also done by the finalizer). | – |
| `iter it f` | *Release* the OCaml runtime lock, then repeatedly call `Iterator::next`. For each frame we *re‑acquire* the lock, build a tiny OCaml record (`alloc_frame`) that contains: <br>• a copy of the 64‑bit timestamp <br>• two ints for lengths <br>• a **read‑only** `Bigarray` that points directly to the C++ buffer <br>Then we invoke the OCaml closure (`caml_callback`). After the callback we release the lock again and continue. | The `while (it->next(cur)) { … }` loop is pure C++ code; the only OCaml interaction per frame is the callback. |
| Accessors (`timestamp`, `captured_len`, …) | Simple field extraction from the record – zero‑cost. | – |

Because the packet data is **not copied** (the bigarray points to the original memory) the per‑frame cost is essentially:

* C++ iterator advance (`next`) – O(1)  
* Build a 4‑field OCaml record (a handful of allocations) – cheap  
* Call the user closure – unavoidable OCaml‑C boundary  

Even for 800 million frames this design is fast enough on modern hardware; the only allocation per frame is the 4‑field record (≈ 32 bytes), which is cheap compared with copying the packet payload.

---

## 3. Build instructions

Assuming the C++ implementation of `libpcapng::Iterator` lives in `libpcapng.cpp` (or is linked from a library), the binding can be built with `ocamlc`/`ocamlopt` as follows:

```bash
# Compile the C++ stub (needs a C++ compiler)
g++ -std=c++17 -I$(ocamlc -where) -fPIC -c pcapng_stubs.c -o pcapng_stubs.o

# If the library is a separate .a/.so, link it now:
# g++ -shared -o libpcapng_stubs.so pcapng_stubs.o libpcapng.a

# Build the OCaml library
ocamlopt -c pcapng.mli          # only the interface
ocamlopt -c pcapng.ml           # (empty – the implementation is in C)

# Archive the C stub with the OCaml code
ocamlopt -a -o libpcapng.cmxa \
    pcapng.cmx pcapng_stubs.o \
    -cclib -lstdc++               # link the C++ std lib

# Or for native code only:
ocamlopt -output-obj -o pcapng.o pcapng.cmx pcapng_stubs.o
```

Now the binding can be used from OCaml:

```ocaml
(* test_pcapng.ml *)
let () =
  let p = Pcapng.open_file "sample.pcapng" in
  Pcapng.iter p (fun frame ->
      let ts = Pcapng.timestamp frame in
      let len = Pcapng.captured_len frame in
      Printf.printf "frame @ %Ld, %d bytes\n%!" ts len
    );
  Pcapng.close p
```

Compile the test program:

```bash
ocamlopt -I . pcapng.cmxa test_pcapng.ml -o test_pcapng
```

Running `./test_pcapng` will walk the whole file, invoking the OCaml closure for each of the (potentially 800 million) frames while keeping the per‑frame overhead minimal.

---

### TL;DR – What you get

* **`type t`** – opaque handle to a pcapng file.  
* **`type frame`** – temporary record passed to the callback (timestamp, lengths, and a zero‑copy `Bigarray` view of the raw bytes).  
* **`iter : t -> (frame -> unit) -> unit`** – the hot path; runs in C++ and only enters OCaml once per frame.  
* **Accessor functions** – cheap, no extra allocation.  

You can now ship a fast, memory‑efficient OCaml binding for a massive‑scale pcapng iterator. Happy hacking!
